const body = $input.first().json.body || $input.first().json;
const articleId = 'art_' + Math.random().toString(36).substring(2, 10) + '_' + Date.now().toString(36);

return [{
  json: {
    article_id: articleId,
    created_at: new Date().toISOString(),
    title: (body.title || '').trim(),
    content: (body.content || '').trim(),
    category: (body.category || '').trim(),
    author: (body.author || '').trim(),
    published_at: (body.published_at || '').trim(),
    tags_csv: (body.tags || '').split(',').map(t => t.trim()).filter(Boolean).join(', '),
    seo_status: 'pending',
    seo_requested_at: new Date().toISOString()
  }
}];

