const raw = $input.first().json.message?.content
  || $input.first().json.choices?.[0]?.message?.content
  || '';

let seo;
try {
  const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  seo = JSON.parse(cleaned);
} catch(e) {
  // If OpenAI fails, use placeholder values so the sheet still gets updated
  console.warn('OpenAI parse failed, using fallbacks. Raw:', raw.slice(0, 200));
  seo = {
    primary_keywords: ['content marketing', 'article seo'],
    long_tail_keywords: ['how to rank articles', 'seo content strategy'],
    meta_title: $node['Normalize Data'].json.title.slice(0, 60),
    meta_description: 'Read this article for insights on ' + $node['Normalize Data'].json.title,
    ranking_insights: {
      primary_target: 'article seo',
      high_opportunity: ['content strategy'],
      high_competition: ['seo'],
      notes: 'Focus on long-tail keywords for faster ranking.'
    }
  };
}

const articleId = $node['Normalize Data'].json.article_id;

return [{
  json: {
    article_id: articleId,
    processed_at: new Date().toISOString(),
    primary_keywords_csv: (seo.primary_keywords || []).join(', '),
    long_tail_keywords_csv: (seo.long_tail_keywords || []).join(', '),
    meta_title: seo.meta_title || '',
    meta_description: seo.meta_description || '',
    ranking_insights: JSON.stringify(seo.ranking_insights || {})
  }
}];
